using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// Train the model at startup
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
var rawData = mlContext.Data.LoadFromTextFile<CustomerCsvRow>(dataPath, hasHeader: true, separatorChar: ',');

// Convert "Yes"/"No" to boolean Label column
var labelMapping = new[] { new YesNoMapping { Churned = "Yes", Label = true }, new YesNoMapping { Churned = "No", Label = false } };
var labelLookup = mlContext.Data.LoadFromEnumerable(labelMapping);

var labelPipeline = mlContext.Transforms.Conversion.MapValue(
    "Label", labelLookup, labelLookup.Schema["Churned"], labelLookup.Schema["Label"], "Churned");

var labeledData = labelPipeline.Fit(rawData).Transform(rawData);
var split = mlContext.Data.TrainTestSplit(labeledData, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label",
        featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

// Evaluate on held-out test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions);
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

// Save and register via thread-safe PredictionEnginePool
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
mlContext.Model.Save(model, labeledData.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

