using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// Train the model at startup and register the prediction engine pool
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
var allData = mlContext.Data.LoadFromTextFile<CustomerInput>(dataPath, hasHeader: true, separatorChar: ',');
var split = mlContext.Data.TrainTestSplit(allData, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerInput.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerInput.Age),
        nameof(CustomerInput.Income),
        "RegionEncoded",
        nameof(CustomerInput.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label",
        featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

// Evaluate on test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions);
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

// Save and register via PredictionEnginePool
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
mlContext.Model.Save(model, allData.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapPost("/predict", (CustomerInput input, PredictionEnginePool<CustomerInput, ChurnPrediction> pool) =>
